  1	import * as React from 'react';
  2	import {
  3	  useYupValidationResolver,
  4	  formSettings,
  5	  TextInputWithFieldRequirements,
  6	  useCustomTranslation,
  7	} from '@odf/shared';
  8	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  9	import { CommonModalProps } from '@odf/shared/modals/common';
 10	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 11	import { useForm, Resolver } from 'react-hook-form';
 12	import { Link, useNavigate } from 'react-router-dom-v5-compat';
 13	import useSWRMutation from 'swr/mutation';
 14	import {
 15	  Form,
 16	  FormGroup,
 17	  TextInput,
 18	  ActionGroup,
 19	  Button,
 20	  Alert,
 21	  FormHelperText,
 22	  FormSection,
 23	  Title,
 24	  Page,
 25	  PageSection,
 26	  PageSectionVariants,
 27	  PageBreadcrumb,
 28	  Breadcrumb,
 29	  BreadcrumbItem,
 30	  TextContent,
 31	  Text,
 32	  HelperText,
 33	  HelperTextItem,
 34	  ButtonType,
 35	  ValidatedOptions,
 36	} from '@patternfly/react-core';
 37	import {
 38	  TAG_VALUE_MAX_LENGTH,
 39	  IAM_BASE_ROUTE,
 40	  CREATE_IAM_USER_MUTATION_KEY,
 41	  POLICY_DOCUMENT,
 42	  POLICY_NAME,
 43	} from '../../../constants/s3-iam';
 44	import {
 45	  AccessKeySecretKeyDisplayModal,
 46	  AccessKeySecretKeyDisplayModalProps,
 47	} from '../../../modals/s3-iam/AccessKeySecretKeyDisplayModal';
 48	import { KeyValuePair } from '../../../types/s3-iam';
 49	import { getKeyValidations, getValueValidations } from '../../../utils/s3-iam';
 50	import useIamUserFormValidation from '../hooks/useIamUserFormValidation';
 51	import { IamContext, IamProvider } from '../iam-context';
 52	import { AddKeyValuePairs } from './AddKeyValuePair';
 53	
 54	type FormData = {
 55	  userName: string;
 56	};
 57	
 58	export const CreateUserFormContent = () => {
 59	  const [descriptionTagValue, setDescriptionTagValue] =
 60	    React.useState<string>('');
 61	  const { iamClient } = React.useContext(IamContext);
 62	  const [pairs, setPairs] = React.useState<KeyValuePair[]>([]);
 63	  const [tagErrors, setTagErrors] = React.useState('');
 64	  const { t } = useCustomTranslation();
 65	  const navigate = useNavigate();
 66	  const launchModal = useModal();
 67	
 68	  const {
 69	    trigger: createUser,
 70	    isMutating: inProgress,
 71	    error: createError,
 72	  } = useSWRMutation(
 73	    CREATE_IAM_USER_MUTATION_KEY,
 74	    async (
 75	      _key,
 76	      {
 77	        arg,
 78	      }: {
 79	        arg: {
 80	          userName: string;
 81	          pairs: KeyValuePair[];
 82	          descriptionTagValue: string;
 83	        };
 84	      }
 85	    ) => {
 86	      const {
 87	        userName: userNameArg,
 88	        pairs: pairsArg,
 89	        descriptionTagValue: descriptionTagValueArg,
 90	      } = arg;
 91	
 92	      const userInput = {
 93	        UserName: userNameArg,
 94	        ...(pairsArg.length !== 0 && { Tags: pairsArg }),
 95	      };
 96	      await iamClient.createIamUser(userInput);
 97	
 98	      const accessKeyResponse = await iamClient.createAccessKey({
 99	        UserName: userNameArg,
100	      });
101	
102	      const allTags: KeyValuePair[] = [...pairsArg];
103	      allTags.push({
104	        Key: accessKeyResponse.AccessKey.AccessKeyId,
105	        Value: descriptionTagValueArg,
106	      });
107	      await iamClient.tagUser({
108	        UserName: userNameArg,
109	        Tags: allTags,
110	      });
111	
112	      await iamClient.putUserPolicy({
113	        UserName: userNameArg,
114	        PolicyDocument: POLICY_DOCUMENT,
115	        PolicyName: POLICY_NAME,
116	      });
117	
118	      return { accessKeyResponse };
119	    }
120	  );
121	
122	  const { userFormSchema, fieldRequirements } = useIamUserFormValidation();
123	  const resolver = useYupValidationResolver(
124	    userFormSchema
125	  ) as unknown as Resolver<FormData>;
126	
127	  const {
128	    control,
129	    handleSubmit,
130	    formState: { isValid, isSubmitted },
131	  } = useForm<FormData>({
132	    ...(formSettings as any),
133	    resolver,
134	    defaultValues: {
135	      userName: '',
136	    },
137	  });
138	
139	  const aggregatedErrorMessage = [
140	    !isValid && isSubmitted && t('Address form validation errors to proceed'),
141	    createError && (createError.message || JSON.stringify(createError)),
142	    tagErrors,
143	  ]
144	    .filter(Boolean)
145	    .join('\n\n');
146	
147	  const save = async (formData: FormData) => {
148	    setTagErrors('');
149	
150	    const { userName } = formData;
151	
152	    let keyError = '';
153	    let valueError = '';
154	
155	    pairs.forEach((pair) => {
156	      const Key = String(pair.Key || '').trim();
157	      const Value = String(pair.Value || '').trim();
158	
159	      const [keyValidationVariant, keyHelperText] = getKeyValidations(Key, t);
160	      const [valueValidationVariant, valueHelperText] = getValueValidations(
161	        Value,
162	        t
163	      );
164	
165	      if (keyValidationVariant === ValidatedOptions.error && !keyError) {
166	        keyError = keyHelperText;
167	      }
168	      if (valueValidationVariant === ValidatedOptions.error && !valueError) {
169	        valueError = valueHelperText;
170	      }
171	    });
172	
173	    const hasTagErrors = keyError !== '' || valueError !== '';
174	
175	    const [descriptionTagValidationVariant, descriptionTagHelperText] =
176	      getValueValidations(descriptionTagValue.trim(), t);
177	    const descriptionTagError =
178	      descriptionTagValidationVariant === ValidatedOptions.error
179	        ? descriptionTagHelperText
180	        : '';
181	
182	    if (hasTagErrors || descriptionTagError !== '') {
183	      let errors = '';
184	
185	      if (hasTagErrors) {
186	        errors = keyError + (valueError ? '\n' + valueError : '');
187	      }
188	
189	      if (descriptionTagError) {
190	        errors =
191	          errors +
192	          (errors ? '\n' : '') +
193	          t('Description tag: ') +
194	          descriptionTagError;
195	      }
196	
197	      setTagErrors(
198	        t('Address tag validation errors before submitting.') + '\n\n' + errors
199	      );
200	      return;
201	    }
202	
203	    try {
204	      const result = await createUser({
205	        userName,
206	        pairs,
207	        descriptionTagValue,
208	      });
209	
210	      if (result?.accessKeyResponse) {
211	        launchModal(AccessKeySecretKeyDisplayModal, {
212	          isOpen: true,
213	          extraProps: {
214	            AccessKeyId: result.accessKeyResponse.AccessKey.AccessKeyId,
215	            SecretKey: result.accessKeyResponse.AccessKey.SecretAccessKey,
216	            title: t('User created successfully'),
217	            buttonText: t('Back to IAM'),
218	            navigateTo: IAM_BASE_ROUTE,
219	          },
220	        } as CommonModalProps<AccessKeySecretKeyDisplayModalProps>);
221	      }
222	    } catch (_error) {
223	      // Error is already caught by useSWRMutation and surfaced via createError in aggregatedErrorMessage
224	    }
225	  };
226	
227	  return (
228	    <Page>
229	      <PageBreadcrumb>
230	        <Breadcrumb>
231	          <BreadcrumbItem>
232	            {inProgress ? (
233	              t('IAM')
234	            ) : (
235	              <Link to={IAM_BASE_ROUTE}>{t('IAM')}</Link>
236	            )}
237	          </BreadcrumbItem>
238	          <BreadcrumbItem isActive>{t('Create user')}</BreadcrumbItem>
239	        </Breadcrumb>
240	      </PageBreadcrumb>
241	      <PageSection variant={PageSectionVariants.light} isFilled>
242	        <Form onSubmit={handleSubmit(save)} className="pf-v6-u-w-75">
243	          <TextContent>
244	            <Title headingLevel="h1">{t('Create user')}</Title>
245	            <Text component="p" className="text-muted">
246	              {t(
247	                'Create users to generate and manage access keys and policies.'
248	              )}
249	            </Text>
250	          </TextContent>
251	          <FormSection>
252	            <Alert
253	              variant="info"
254	              title={t('Creating user will generate access key and secret key')}
255	              ouiaId="InfoAlert"
256	            />
257	
258	            <TextInputWithFieldRequirements
259	              control={control as any}
260	              fieldRequirements={fieldRequirements}
261	              popoverProps={{
262	                headerContent: t('Name requirements'),
263	                footerContent: t('Example: my-user'),
264	              }}
265	              formGroupProps={{
266	                label: t('Username'),
267	                fieldId: 'user-name',
268	                isRequired: true,
269	              }}
270	              textInputProps={{
271	                id: 'user-name',
272	                name: 'userName',
273	                type: 'text',
274	                placeholder: t('Input field'),
275	                'aria-describedby': 'user-name-help',
276	                'data-test': 'user-name',
277	              }}
278	            />
279	
280	            <AddKeyValuePairs pairs={pairs} setPairs={setPairs} />
281	
282	            <FormGroup>
283	              <label className="pf-v6-u-pt-sm">
284	                {t('Description tag')}
285	                <div className="pf-v6-u-pt-md">{t('Value')}</div>
286	              </label>
287	              <TextInput
288	                type="text"
289	                placeholder={t('Input field')}
290	                value={descriptionTagValue}
291	                onChange={(_event, value) => setDescriptionTagValue(value)}
292	                className="pf-v6-u-w-50"
293	                isDisabled={!isValid}
294	              />
295	              <FormHelperText>
296	                <HelperText>
297	                  <HelperTextItem>
298	                    {t(
299	                      `Maximum allowed characters - ${TAG_VALUE_MAX_LENGTH}. Use combination of letters, numbers, special characters`
300	                    )}
301	                  </HelperTextItem>
302	                </HelperText>
303	              </FormHelperText>
304	            </FormGroup>
305	
306	            <ButtonBar
307	              errorMessage={aggregatedErrorMessage}
308	              inProgress={inProgress}
309	            >
310	              <ActionGroup className="pf-v6-c-form">
311	                <Button
312	                  isDisabled={!isValid || inProgress}
313	                  isLoading={inProgress}
314	                  variant="primary"
315	                  type={ButtonType.submit}
316	                  data-test="create-user"
317	                >
318	                  {t('Create')}
319	                </Button>
320	                <Button
321	                  variant="plain"
322	                  onClick={() => navigate(IAM_BASE_ROUTE)}
323	                  type="button"
324	                  isDisabled={inProgress}
325	                >
326	                  {t('Cancel')}
327	                </Button>
328	              </ActionGroup>
329	            </ButtonBar>
330	          </FormSection>
331	        </Form>
332	      </PageSection>
333	    </Page>
334	  );
335	};
336	
337	const CreateUserForm = () => {
338	  return (
339	    <IamProvider>
340	      <CreateUserFormContent />
341	    </IamProvider>
342	  );
343	};
344	
345	export default CreateUserForm;

